"""
Encoders for encoding categorical variables and scaling continuous data.
"""
from typing import Any, Callable, Dict, Iterable, List, Tuple, Union, Optional
import warnings
import numpy as np
import pandas as pd
from copy import deepcopy
from sklearn.base import BaseEstimator, TransformerMixin
import torch
from torch.distributions import constraints
from torch.distributions.transforms import ExpTransform, PowerTransform, SigmoidTransform, Transform, _clipped_sigmoid
import torch.nn.functional as F
from torch.nn.utils import rnn
from pytorch_forecasting.utils import InitialParameterRepresenterMixIn

def _plus_one(x):
    return x + 1

def _minus_one(x):
    return x - 1

def _identity(x):
    return x

def _clipped_logit(x):
    finfo = torch.finfo(x.dtype)
    x = x.clamp(min=finfo.eps, max=1.0 - finfo.eps)
    return x.log() - (-x).log1p()

def softplus_inv(y):
    finfo = torch.finfo(y.dtype)
    return y.where(y > 20.0, y + (y + finfo.eps).neg().expm1().neg().log())

def _square(y):
    return torch.pow(y, 2.0)

def _clipped_log(y):
    finfo = torch.finfo(y.dtype)
    return y.log().clamp(min=-1 / finfo.eps)

class SoftplusTransform(Transform):
    """
    Transform via the mapping :math:`\\text{Softplus}(x) = \\log(1 + \\exp(x))`.
    The implementation reverts to the linear function when :math:`x > 20`.
    """
    domain = constraints.real
    codomain = constraints.positive
    bijective = True
    sign = +1

    def __eq__(self, other):
        return isinstance(other, SoftplusTransform)

    def _call(self, x):
        return F.softplus(x)

    def _inverse(self, y):
        return softplus_inv(y)

def transform_values(
    self,
    name: str,
    values: Union[pd.Series, torch.Tensor, np.ndarray],
    data: pd.DataFrame = None,
    inverse=False,
    group_id: bool = False,
    **kwargs,
) -> np.ndarray:
    """
    Scale and encode values.

    Args:
        name (str): name of variable
        values (Union[pd.Series, torch.Tensor, np.ndarray]): values to encode/scale
        data (pd.DataFrame, optional): extra data used for scaling (e.g. dataframe with groups columns).
            Defaults to None.
        inverse (bool, optional): if to conduct inverse transformation. Defaults to False.
        group_id (bool, optional): If the passed name refers to a group id (different encoders are used for these).
            Defaults to False.
        **kwargs: additional arguments for transform/inverse_transform method

    Returns:
        np.ndarray: (de/en)coded/(de)scaled values
    """
    transformer = self.get_transformer(name, group_id=group_id)
    if transformer is None:
        return values
    if inverse:
        transform = transformer.inverse_transform
    else:
        transform = transformer.transform

    if group_id:
        name = self._group_ids_mapping[name]
    # remaining categories
    if name in self.flat_categoricals + self.group_ids + self._group_ids:
        return transform(values, **kwargs)

    # reals
    elif name in self.reals:
        if isinstance(transformer, GroupNormalizer):
            return transform(values, data, **kwargs)
        elif isinstance(transformer, EncoderNormalizer):
            return transform(values, **kwargs)
        else:
            if isinstance(values, pd.Series):
                values = values.to_frame()
                return np.asarray(transform(values, **kwargs)).reshape(-1)
            else:
                values = values.reshape(-1, 1)
                return transform(values, **kwargs).reshape(-1)
    else:
        return values

def _data_to_tensors(self, data: pd.DataFrame) -> Dict[str, torch.Tensor]:
    """
    Convert data to tensors for faster access with :py:meth:`~__getitem__`.

    Args:
        data (pd.DataFrame): preprocessed data

    Returns:
        Dict[str, torch.Tensor]: dictionary of tensors for continous, categorical data, groups, target and
            time index
    """

    index = check_for_nonfinite(
        torch.tensor(data[self._group_ids].to_numpy(np.int64), dtype=torch.int64), self.group_ids
    )

    def log_abs_det_jacobian(self, x, y):
        return -F.softplus(-x)

class Expm1Transform(ExpTransform):
    codomain = constraints.greater_than_eq(-1.0)

    def _call(self, x):
        return super()._call(x) - 1.0

    def _inverse(self, y):
        return super()._inverse(y + 1.0)

class MinusOneTransform(Transform):
    """
    Transform x -> x - 1.
    """
    domain = constraints.real
    codomain = constraints.real
    sign: int = 1
    bijective: bool = True

    def _call(self, x):
        return x - 1.0

    def _inverse(self, y):
        return y + 1.0

    def log_abs_det_jacobian(self, x, y):
        return 0.0

class ReLuTransform(Transform):
    """
    Transform x -> max(0, x).
    """
    domain = constraints.real
    codomain = constraints.nonnegative
    sign: int = 1
    bijective: bool = False

    def _call(self, x):
        return F.relu(x)

    def _inverse(self, y):
        return y

    def log_abs_det_jacobian(self, x, y):
        return 0.0

class TransformMixIn:
    """Mixin for providing pre- and post-processing capabilities to encoders.

    Class should have a ``transformation`` attribute to indicate how to preprocess data.
    """
    TRANSFORMATIONS = {'log': dict(forward=_clipped_log, reverse=torch.exp, inverse_torch=ExpTransform()), 'log1p': dict(forward=torch.log1p, reverse=torch.exp, inverse=torch.expm1, inverse_torch=Expm1Transform()), 'logit': dict(forward=_clipped_logit, reverse=_clipped_sigmoid, inverse_torch=SigmoidTransform()), 'count': dict(forward=_plus_one, reverse=F.softplus, inverse=_minus_one, inverse_torch=MinusOneTransform()), 'softplus': dict(forward=softplus_inv, reverse=F.softplus, inverse_torch=SoftplusTransform()), 'relu': dict(forward=_identity, reverse=F.relu, inverse=_identity, inverse_torch=ReLuTransform()), 'sqrt': dict(forward=torch.sqrt, reverse=_square, inverse_torch=PowerTransform(exponent=2.0))}

    @classmethod
    def get_transform(cls, transformation: Union[str, Dict[str, Callable]]) -> Dict[str, Callable]:
        """Return transformation functions.

        Args:
            transformation (Union[str, Dict[str, Callable]]): name of transformation or
                dictionary with transformation information.

        Returns:
            Dict[str, Callable]: dictionary with transformation functions (forward, reverse, inverse and inverse_torch)
        """
        if isinstance(transformation, str):
            transform = cls.TRANSFORMATIONS[transformation]
        else:
            transform = transformation
        transform.setdefault('forward', _identity)
        transform.setdefault('reverse', _identity)
        return transform
